import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import orderService from '../../services/orderService';

const DASHBOARD_ORDERS_CACHE_KEY = 'dashboard_orders_cache_v1';

const readCachedOrders = () => {
    try {
        const raw = localStorage.getItem(DASHBOARD_ORDERS_CACHE_KEY);
        const parsed = raw ? JSON.parse(raw) : null;
        return Array.isArray(parsed?.orders) ? parsed.orders : [];
    } catch {
        return [];
    }
};

export default function DashboardOrders() {
    const [orders, setOrders] = useState(() => readCachedOrders());
    const [loadingOrders, setLoadingOrders] = useState(() => readCachedOrders().length === 0);
    const [downloadingOrderId, setDownloadingOrderId] = useState(null);

    const extractOrderItems = (order) => {
        if (Array.isArray(order?.items)) {
            return order.items;
        }

        if (Array.isArray(order?.order_items)) {
            return order.order_items;
        }

        return [];
    };

    const orderProductsLabel = (order) => {
        const items = extractOrderItems(order);

        if (items.length === 0) {
            return 'Products will show after checkout sync.';
        }

        const names = items
            .map((item) => item?.product?.name || item?.name || '')
            .filter((name) => String(name).trim().length > 0);

        if (names.length === 0) {
            return `${items.length} item${items.length === 1 ? '' : 's'} checked out`;
        }

        const preview = names.slice(0, 2).join(', ');
        const remaining = names.length - 2;
        return remaining > 0 ? `${preview} +${remaining} more` : preview;
    };

    const withTimeout = (promise, ms = 6000) => {
        const timeoutPromise = new Promise((_, reject) => {
            window.setTimeout(() => reject(new Error('Request timeout')), ms);
        });

        return Promise.race([promise, timeoutPromise]);
    };

    const loadOrders = async () => {
        try {
            setLoadingOrders(true);
            const res = await withTimeout(orderService.getOrders({ page: 1, include_items: true }));
            const rows = res?.data?.data?.data || [];
            setOrders(rows);
            localStorage.setItem(DASHBOARD_ORDERS_CACHE_KEY, JSON.stringify({ orders: rows }));
        } catch {
            if ((orders || []).length === 0) {
                setOrders(readCachedOrders());
            }
        } finally {
            setLoadingOrders(false);
        }
    };

    useEffect(() => {
        loadOrders();
    }, []);

    const downloadReceipt = (order) => {
        if (!order) {
            return;
        }

        setDownloadingOrderId(order.id);

        try {
            const lines = [];
            lines.push('CarVex Receipt');
            lines.push(`Order Number: ${order.order_number || order.id}`);
            lines.push(`Date: ${new Date(order.created_at).toLocaleString()}`);
            lines.push('');
            lines.push(`Shipping Address: ${order.shipping_address || 'N/A'}`);
            lines.push(`Payment Method: ${(order.payment_method || 'cod').toUpperCase()}`);
            lines.push(`Payment Status: ${order.payment_status || 'pending'}`);
            lines.push(`Total Amount: ₱${Number(order.total_amount || 0).toFixed(2)}`);

            const blob = new Blob([lines.join('\n')], { type: 'text/plain;charset=utf-8' });
            const url = window.URL.createObjectURL(blob);
            const link = document.createElement('a');
            link.href = url;
            link.download = `carvex-receipt-${order.order_number || order.id}.txt`;
            document.body.appendChild(link);
            link.click();
            link.remove();
            window.URL.revokeObjectURL(url);
        } finally {
            setDownloadingOrderId(null);
        }
    };

    return (
        <div className="dashboard-grid">
            <section className="dashboard-panel">
                <h2>Order History</h2>
                {loadingOrders && orders.length === 0 ? (
                    <p className="muted">Loading orders...</p>
                ) : orders.length === 0 ? (
                    <p className="muted">No order history yet.</p>
                ) : (
                    <div className="dashboard-order-list">
                        {orders.map((order) => (
                            <article key={order.id} className="dashboard-order-item">
                                <div className="dashboard-order-item__content">
                                    <div className="dashboard-order-item__header">
                                        <strong>{order.order_number || `Order #${order.id}`}</strong>
                                        <span className={`order-status status-${order.status || 'processing'}`}>{order.status || 'processing'}</span>
                                    </div>
                                    <p>{new Date(order.created_at).toLocaleDateString()}</p>
                                    <p className="muted dashboard-order-item__products">
                                        {orderProductsLabel(order)}
                                    </p>
                                </div>
                                <div className="dashboard-order-item__actions">
                                    <strong className="dashboard-order-item__total">₱{Number(order.total_amount || 0).toFixed(2)}</strong>
                                    <Link
                                        to={`/dashboard/orders/${order.id}`}
                                        state={{ order }}
                                        className="btn btn-primary btn-sm"
                                    >
                                        Track Order
                                    </Link>
                                    <button
                                        type="button"
                                        className="btn btn-outline-primary btn-sm"
                                        onClick={() => downloadReceipt(order)}
                                        disabled={downloadingOrderId === order.id}
                                    >
                                        {downloadingOrderId === order.id ? 'Downloading...' : 'Download Receipt'}
                                    </button>
                                </div>
                            </article>
                        ))}
                    </div>
                )}

                <div style={{ marginTop: '0.9rem' }}>
                    <Link to="/customer-service" className="btn btn-outline-primary btn-sm">
                        Need Help? Contact Support
                    </Link>
                </div>
            </section>
        </div>
    );
}
